INSERT INTO customer_notes (id, customer_id, content, created_at, updated_at) VALUES
('ca000001-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'Paciente relata melhora significativa na qualidade do sono após início do uso de melatonina. Mantém queixa de ansiedade em situações de avaliação no trabalho. Sugiro trabalhar técnicas de respiração e reestruturação cognitiva nas próximas sessões.', '2025-12-20 10:30:00', '2025-12-20 10:30:00'),
('ca000002-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'Maria compareceu acompanhada da irmã. Relata que tem conseguido aplicar as técnicas de respiração diafragmática nos momentos de crise. Episódios de insônia reduziram de 4-5 para 1-2 vezes por semana. Humor estável.', '2026-01-10 14:00:00', '2026-01-10 14:00:00'),
('ca000003-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'Sessão focada em reestruturação cognitiva sobre crenças de desempenho profissional. Paciente identificou padrão de pensamento catastrófico em relação a avaliações de desempenho. Trabalhou-se registro de pensamentos automáticos.', '2026-01-24 09:15:00', '2026-01-24 09:15:00'),
('ca000004-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'Paciente relata episódio de crise de ansiedade no trabalho na semana anterior, mas conseguiu manejar utilizando técnicas aprendidas em sessão. Demonstra progresso no autoconhecimento e autorregulação emocional.', '2026-02-07 10:00:00', '2026-02-07 10:00:00'),
('ca000005-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'Reavaliação com BAI: escore reduziu de 28 (moderado) para 16 (leve). BDI-II manteve-se estável em 12 (leve). Evolução positiva. Discutido com paciente possibilidade de redução para frequência quinzenal.', '2026-02-21 14:30:00', '2026-02-21 14:30:00'),
('ca000006-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'Paciente concordou com a transição para sessões quinzenais. Relatou que se sente mais confiante no ambiente de trabalho e que o relacionamento com colegas melhorou. Sono normalizado na maior parte dos dias.', '2026-03-07 10:00:00', '2026-03-07 10:00:00');
INSERT INTO customer_events (id, customer_id, type, title, description, date, created_at) VALUES
('cb000001-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'avaliacao', 'Avaliação psicológica inicial', 'Primeira sessão de avaliação. Aplicados BAI (escore 28 - moderado) e BDI-II (escore 14 - leve). Entrevista clínica semiestruturada realizada.', '2025-12-01 09:00:00', '2025-12-01 09:00:00'),
('cb000002-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'avaliacao', 'Segunda sessão de avaliação', 'Continuidade da avaliação. Aplicação de testes complementares e aprofundamento da história clínica.', '2025-12-05 09:00:00', '2025-12-05 09:00:00'),
('cb000003-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'laudo', 'Entrega do laudo psicológico', 'Devolutiva dos resultados da avaliação e entrega do laudo. Paciente ciente do diagnóstico e das recomendações de tratamento.', '2025-12-15 10:00:00', '2025-12-15 10:00:00'),
('cb000004-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'consulta', 'Início do acompanhamento psicoterapêutico', 'Primeira sessão de psicoterapia (TCC). Estabelecimento do contrato terapêutico e definição dos objetivos iniciais.', '2025-12-20 10:30:00', '2025-12-20 10:30:00'),
('cb000005-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'consulta', 'Sessão de psicoterapia', 'Trabalho com técnicas de respiração diafragmática e relaxamento muscular progressivo.', '2026-01-03 10:30:00', '2026-01-03 10:30:00'),
('cb000006-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'retorno', 'Retorno com acompanhante', 'Maria compareceu acompanhada da irmã. Evolução positiva nos sintomas de insônia.', '2026-01-10 14:00:00', '2026-01-10 14:00:00'),
('cb000007-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'consulta', 'Sessão de reestruturação cognitiva', 'Foco em crenças disfuncionais sobre desempenho profissional. Registro de pensamentos automáticos.', '2026-01-24 09:15:00', '2026-01-24 09:15:00'),
('cb000008-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'consulta', 'Sessão de psicoterapia', 'Paciente relatou manejo adequado de crise de ansiedade no trabalho. Reforço positivo das estratégias de enfrentamento.', '2026-02-07 10:00:00', '2026-02-07 10:00:00'),
('cb000009-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'avaliacao', 'Reavaliação psicométrica', 'Reaplicação do BAI (escore 16 - leve) e BDI-II (escore 12 - leve). Melhora significativa nos índices de ansiedade.', '2026-02-21 14:30:00', '2026-02-21 14:30:00'),
('cb000010-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'consulta', 'Sessão de psicoterapia - transição quinzenal', 'Acordada redução da frequência para sessões quinzenais. Paciente demonstra autonomia na aplicação das técnicas.', '2026-03-07 10:00:00', '2026-03-07 10:00:00'),
('cb000011-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'observacao', 'Contato telefônico', 'Maria ligou para informar que está se sentindo bem e que não houve episódios de crise desde a última sessão. Confirmada próxima sessão quinzenal.', '2026-03-14 16:00:00', '2026-03-14 16:00:00');
